const ICONS = {
  info: () => <span>ℹ️</span>,
  warning: () => <span>⚠️</span>,
  error: () => <span>⛔</span>,
};

function NotificationIcon({ type }) {
  const Icon = ICONS[type] ?? ICONS.info;
  return <Icon />;
}

console.log(renderToStaticMarkup(<NotificationIcon type="warning" />));

